mapper.sql:
where ld.DATA_NAME is not null

    AND ld.HDQR_BOB_DCD = #{searchTarget}


    AND ld.LEARNING_TYPE = #{searchLearningType}


    AND (ld.DATA_NAME LIKE CONCAT('%', #{searchKeyword}, '%')
            or t.TEMPLATE_NAME LIKE CONCAT('%', #{searchKeyword}, '%')
            or hm.MEM_NAME LIKE CONCAT('%', #{searchKeyword}, '%'))


    AND ${searchRegex}
